/**
 * Helper class for MinHeap implementation required for Dijkstra's algorithm.
 * Stores elements as [priority1, priority2, data...]
 * We prioritize minimum priority1, then minimum priority2.
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Custom comparator: Compares based on the first element (t), then the second element (-c).
    // We want minimum t, then minimum -c (which means maximum c).
    compare(a, b) {
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Min time
        }
        return a[1] - b[1]; // Min negative color (Max color)
    }

    push(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(this.heap[currentIndex], this.heap[parentIndex]) < 0) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return root;
    }

    bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let leftIdx = this.getLeftChildIndex(currentIndex);
            let rightIdx = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Compare with left child
            if (leftIdx <= lastIndex && this.compare(this.heap[leftIdx], this.heap[smallest]) < 0) {
                smallest = leftIdx;
            }

            // Compare with right child
            if (rightIdx <= lastIndex && this.compare(this.heap[rightIdx], this.heap[smallest]) < 0) {
                smallest = rightIdx;
            }

            if (smallest !== currentIndex) {
                this.swap(currentIndex, smallest);
                currentIndex = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, m, sources) {
    // Dist[r][c]: Minimum time to reach (r, c)
    // Color[r][c]: Maximum color that reaches (r, c) at Dist[r][c]
    const Dist = Array(n).fill(0).map(() => Array(m).fill(Infinity));
    const Color = Array(n).fill(0).map(() => Array(m).fill(0));

    const pq = new MinPriorityQueue();

    // Initialize sources
    for (const [r, c, color] of sources) {
        if (Dist[r][c] > 0) { // Should only happen if sources list has duplicates, which prompt guarantees against.
             // But handle initial state setting robustly
        }
        Dist[r][c] = 0;
        Color[r][c] = color;

        // PQ element: [time, negative_color, row, col]
        // We use negative_color so that min-heap minimizes negative_color, effectively maximizing color.
        pq.push([0, -color, r, c]);
    }

    const dr = [-1, 1, 0, 0];
    const dc = [0, 0, -1, 1];

    while (!pq.isEmpty()) {
        const [t, neg_c, r, c] = pq.pop();
        const current_color = -neg_c;

        // Check for stale entry based on the established best path to (r, c)
        // If the time in the PQ is worse than known best time, skip.
        if (t > Dist[r][c]) continue;
        // If the time is the same, but the color is worse than known best color, skip.
        if (t === Dist[r][c] && current_color < Color[r][c]) continue;


        // Explore neighbors
        for (let i = 0; i < 4; i++) {
            const nr = r + dr[i];
            const nc = c + dc[i];

            // Boundary check
            if (nr < 0 || nr >= n || nc < 0 || nc >= m) continue;

            const t_new = t + 1;
            const c_new = current_color;

            // Relaxation logic

            // 1. Shorter time found: Always update and push
            if (t_new < Dist[nr][nc]) {
                Dist[nr][nc] = t_new;
                Color[nr][nc] = c_new;
                pq.push([t_new, -c_new, nr, nc]);
            } 
            // 2. Same time found: Update only if the color is strictly higher
            else if (t_new === Dist[nr][nc]) {
                if (c_new > Color[nr][nc]) {
                    Color[nr][nc] = c_new;
                    // Since the color improved at the same time, we must re-push this state 
                    // as it might allow propagation of a higher color further out at the same time step.
                    pq.push([t_new, -c_new, nr, nc]);
                }
            }
            // 3. Longer time found: Ignore
        }
    }

    // Format the output
    const result = [];
    for (let r = 0; r < n; r++) {
        const row = [];
        for (let c = 0; c < m; c++) {
            row.push(Color[r][c]);
        }
        result.push(row);
    }

    return result;
}

