import java.util.*;

public class Solution {

    // Helper class to represent a state in the priority queue
    static class State {
        long time;
        long color;
        int r;
        int c;

        public State(long time, long color, int r, int c) {
            this.time = time;
            this.color = color;
            this.r = r;
            this.c = c;
        }
    }

    public static long[][] solve(long n, long m, long[][] sources) {

        // Dist[r][c]: Minimum time to reach (r, c). Since time <= N*M <= 10^5, int is fine, but using long for safety/consistency.
        long[][] dist = new long[(int)n][(int)m];
        // Color[r][c]: Maximum color that reaches (r, c) at Dist[r][c]
        long[][] finalColors = new long[(int)n][(int)m];

        // Initialize distances to infinity (a large value)
        long INF = Long.MAX_VALUE;
        for (int i = 0; i < n; i++) {
            Arrays.fill(dist[i], INF);
        }
        // Colors are initialized to 0 by default in Java for long arrays

        // Priority Queue stores State objects. We want a Min-Heap based on Time, then Max-Heap based on Color.
        PriorityQueue<State> pq = new PriorityQueue<>(
            (s1, s2) -> {
                // 1. Compare Time (Min Time first)
                if (s1.time != s2.time) {
                    return Long.compare(s1.time, s2.time);
                }
                // 2. Compare Color (Max Color first)
                // Since PriorityQueue is a Min-Heap, we compare s2.color - s1.color to achieve Max Heap behavior for color.
                return Long.compare(s2.color, s1.color);
            }
        );

        // Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            long color = source[2];

            if (dist[r][c] > 0) {
                 // Handle initial state setting robustly, though problem statement guarantees unique sources
            }

            dist[r][c] = 0;
            finalColors[r][c] = color;
            pq.offer(new State(0, color, r, c));
        }

        int[] dr = {0, 0, 1, -1};
        int[] dc = {1, -1, 0, 0};

        while (!pq.isEmpty()) {
            State current = pq.poll();
            long t = current.time;
            long c = current.color;
            int r = current.r;
            int c_coord = current.c; // Renamed variable to avoid conflict with loop counter c

            // Check for stale entry
            // If we found a path that is slower, skip.
            if (t > dist[r][c_coord]) continue;
            // If time is equal, but the color is worse than the recorded best color, skip.
            if (t == dist[r][c_coord] && c < finalColors[r][c_coord]) continue;


            // Explore neighbors
            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c_coord + dc[i];

                // Boundary check
                if (nr < 0 || nr >= n || nc < 0 || nc >= m) continue;

                long t_new = t + 1;
                long c_new = c;

                // Relaxation logic

                // Case 1: Shorter time found (Strictly better path)
                if (t_new < dist[nr][nc]) {
                    dist[nr][nc] = t_new;
                    finalColors[nr][nc] = c_new;
                    pq.offer(new State(t_new, c_new, nr, nc));
                } 
                // Case 2: Same time found (Potential color improvement)
                else if (t_new == dist[nr][nc]) {
                    if (c_new > finalColors[nr][nc]) {
                        finalColors[nr][nc] = c_new;
                        // Re-push to allow propagation of this higher color
                        pq.offer(new State(t_new, c_new, nr, nc));
                    }
                }
                // Case 3: Longer time found (Ignore)
            }
        }

        return finalColors;
    }
}

