class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    getParentIndex(i) { return Math.floor((i - 1) / 2); }
    getLeftChildIndex(i) { return 2 * i + 1; }
    getRightChildIndex(i) { return 2 * i + 2; }

    swap(i, j) {
        [this.heap[i], this.heap[j]] = [this.heap[j], this.heap[i]];
    }

    // Custom comparator: Compares based on the first element (t), then the second element (-c).
    // We want minimum t, then minimum -c (which means maximum c).
    compare(a, b) {
        if (a[0] !== b[0]) {
            return a[0] - b[0]; // Min time
        }
        return a[1] - b[1]; // Min negative color (Max color)
    }

    push(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    bubbleUp(index) {
        let currentIndex = index;
        while (currentIndex > 0) {
            const parentIndex = this.getParentIndex(currentIndex);
            if (this.compare(this.heap[currentIndex], this.heap[parentIndex]) < 0) {
                this.swap(currentIndex, parentIndex);
                currentIndex = parentIndex;
            } else {
                break;
            }
        }
    }

    pop() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const root = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return root;
    }

    bubbleDown(index) {
        let currentIndex = index;
        const lastIndex = this.heap.length - 1;

        while (true) {
            let leftIdx = this.getLeftChildIndex(currentIndex);
            let rightIdx = this.getRightChildIndex(currentIndex);
            let smallest = currentIndex;

            // Compare with left child
            if (leftIdx <= lastIndex && this.compare(this.heap[leftIdx], this.heap[smallest]) < 0) {
                smallest = leftIdx;
