import java.util.PriorityQueue;
import java.util.Arrays;

public class Solution {

    // Helper class to represent the state in the Priority Queue
    static class State implements Comparable<State> {
        // t: time (distance), should be minimized
        long time; 
        // negC: negative color, should be minimized (which maximizes actual color C)
        long negC; 
        int r;
        int c;

        public State(long time, long negC, int r, int c) {
            this.time = time;
            this.negC = negC;
            this.r = r;
            this.c = c;
        }

        @Override
        public int compareTo(State other) {
            // 1. Compare by time (min heap)
            if (this.time != other.time) {
                return Long.compare(this.time, other.time);
            }
            // 2. If times are equal, compare by negC (min heap for negC -> max heap for color)
            return Long.compare(this.negC, other.negC);
        }
    }

