import java.util.PriorityQueue;
import java.util.Comparator;
import java.util.Arrays;

public class Solution {

    // Helper class to represent a state in the priority queue
    static class State {
        long time;
        long negativeColor; // Store -color to achieve max color using min heap
        int r;
        int c;

        public State(long time, long negativeColor, int r, int c) {
            this.time = time;
            this.negativeColor = negativeColor;
            this.r = r;
            this.c = c;
        }
    }

    public static long[][] solve(long nLong, long mLong, long[][] sources) {
        // Since N*M <= 10^5, we can safely cast N and M to int for array indexing.
        int N = (int) nLong;
        int M = (int) mLong;

        // Dist[r][c]: Minimum time to reach (r, c). Initialize to infinity.
        // Since max time is < 10^5, Integer.MAX_VALUE is sufficient.
        long[][] dist = new long[N][M];
        for (int i = 0; i < N; i++) {
            Arrays.fill(dist[i], Long.MAX_VALUE);
        }

        // Color[r][c]: Maximum color that reaches (r, c) at dist[r][c].
        long[][] color = new long[N][M]; // Stores final color, matching return type requirement

        // Priority Queue for Dijkstra's algorithm
        // Comparator: Prioritize minimum time, then maximum color (minimum negativeColor)
        PriorityQueue<State> pq = new PriorityQueue<>(Comparator
                .comparingLong((State s) -> s.time)
                .thenComparingLong(s -> s.negativeColor));

        // Initialize sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            long c_val = source[2];

            dist[r][c] = 0;
            color[r][c] = c_val;

            // PQ element: [time=0, negative_color=-c_val, r, c]
            pq.add(new State(0, -c_val, r, c));
        }

        int[] dr = {0, 0, 1, -1};
        int[] dc = {1, -1, 0, 0};

        while (!pq.isEmpty()) {
            State current = pq.poll();
            long t = current.time;
            long current_color = -current.negativeColor;
            int r = current.r;
            int c = current.c;

            // Check for stale entry based on established best path
            // 1. If a faster path exists, skip.
            if (t > dist[r][c]) continue;
            // 2. If time is the same, but the color received is worse than what is recorded, skip.
            // (Note: If t == dist[r][c], current_color should equal color[r][c] if this is the best path, 
            // but we check this for robustness against outdated PQ entries)
            if (t == dist[r][c] && current_color < color[r][c]) continue;


            // Explore neighbors
            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                // Boundary check
                if (nr < 0 || nr >= N || nc < 0 || nc >= M) continue;

                long t_new = t + 1;
                long c_new = current_color;

                // Relaxation logic

                // Case 1: Shorter time found (Standard Dijkstra relaxation)
                if (t_new < dist[nr][nc]) {
                    dist[nr][nc] = t_new;
                    color[nr][nc] = c_new;
                    pq.add(new State(t_new, -c_new, nr, nc));
                } 
                // Case 2: Same time found (Color tie-breaking)
                else if (t_new == dist[nr][nc]) {
                    if (c_new > color[nr][nc]) {
                        // Found a higher color reaching at the fastest possible time. Update and propagate.
                        color[nr][nc] = c_new;
                        // Must re-push the state because this improved color might affect subsequent cells 
                        // reached at time t_new + 1.
                        pq.add(new State(t_new, -c_new, nr, nc));
                    }
                }
                // Case 3: Longer time found (Ignore)
            }
        }

        // Return the final color grid
        return color;
    }
}

