        // Color[r][c]: Maximum color that reaches (r, c) at Dist[r][c]
        long[][] colorGrid = new long[N][M];

        // Initialize distances to infinity (a large number)
        final long INF = Long.MAX_VALUE;
        for (int i = 0; i < N; i++) {
            Arrays.fill(dist[i], INF);
        }

        // Priority Queue: Min Time, then Max Color
        PriorityQueue<State> pq = new PriorityQueue<>(
            (s1, s2) -> {
                // Primary sort: Minimum time
                if (s1.time != s2.time) {
                    return Long.compare(s1.time, s2.time);
                }
                // Secondary sort: Maximum color (descending color)
                return Long.compare(s2.color, s1.color);
            }
